// src/features/review/review.validation.ts
import { z as z4 } from "zod";
var createReviewSchema = z4.object({
  gearItemId: z4.string().min(1),
  rating: z4.number().int().min(1).max(5),
  comment: z4.string().optional()
});

// src/features/review/review.service.ts
var createReview = async (userId, data) => {
  const gear = await prisma.gearItem.findUnique({ where: { id: data.gearItemId } });
  if (!gear) throw new AppError("Gear not found", 404);
  const rental = await prisma.rentalOrder.findFirst({
    where: { customerId: userId, rentalItems: { some: { gearItemId: data.gearItemId } }, status: "RETURNED" }
  });
  if (!rental) throw new AppError("You must rent and return this gear before reviewing", 400);
  const existing = await prisma.review.findUnique({
    where: { userId_gearItemId: { userId, gearItemId: data.gearItemId } }
  });
  if (existing) throw new AppError("You already reviewed this gear", 409);
  return prisma.review.create({
    data: { ...data, userId },
    include: { user: { select: { id: true, name: true } } }
  });
};

// src/features/review/review.controller.ts
var createReview2 = async (req, res, next) => {
  try {
    const parsed = createReviewSchema.safeParse(req.body);
    if (!parsed.success) return sendError(res, "Validation failed", 400, parsed.error.flatten().fieldErrors);
    const review = await createReview(req.user.userId, parsed.data);
    sendSuccess(res, review, "Review created", 201);
  } catch (err) {
    next(err);
  }
};

